const now    = new Date();
const monday = new Date(now);
monday.setDate(now.getDate() - ((now.getDay() + 6) % 7));
monday.setHours(0, 0, 0, 0);

const friday = new Date(monday);
friday.setDate(monday.getDate() + 4);
friday.setHours(23, 59, 59, 999);

// ── ADD THIS ──────────────────────────────────────────────────
// Shift boundaries 3 hours back to represent EAT midnight in UTC
// Monday 00:00 EAT = Sunday 21:00 UTC
// Friday 23:59 EAT = Friday 20:59 UTC
const EAT_OFFSET_MS = 3 * 60 * 60 * 1000;
const mondayEAT = new Date(monday.getTime() - EAT_OFFSET_MS);
const fridayEAT = new Date(friday.getTime() - EAT_OFFSET_MS);
const ceilingEAT = new Date(Math.min(fridayEAT.getTime(), now.getTime()));
// ─────────────────────────────────────────────────────────────

const events = $input.all().map(i => i.json);

const filtered = events.filter(event => {
  if (!event.start?.dateTime) return false;

  const start = new Date(event.start.dateTime); // JS parses +03:00 → UTC internally
  const end   = new Date(event.end?.dateTime || event.start.dateTime);

  if (start < mondayEAT || start > ceilingEAT) return false; // ← use EAT boundaries

  const hours = (end - start) / 3600000;
  if (hours <= 0) return false;

  const selfStatus = (event.attendees || []).find(a => a.self)?.responseStatus;
  if (selfStatus === 'declined') return false;

  return true;
});

const weekStart = monday.toDateString();
const weekEnd   = friday.toDateString();

const cleanEvents = filtered.map(event => ({
  title:       event.summary || '(No title)',
  description: event.description || '',
  start:       event.start.dateTime,
  end:         event.end?.dateTime || event.start.dateTime,
  attendees:   (event.attendees || []).map(a => a.email).join(', ')
}));

if (cleanEvents.length === 0) {
  return [{ json: { weekStart, weekEnd, events: [], empty: true } }];
}

return [{ json: { weekStart, weekEnd, events: cleanEvents, empty: false } }];

const COMPANIES = [
  'All', 'Angaza', 'Biolite', 'Credify', 'EcoWaka',
  'Farm to Feed', 'FarmSky', 'Flowt (New VB)', 'Giraffe Bioenergy',
  'GreenBay', 'Gridless', 'Instollar', 'Lori', 'Nithio',
  'PowerUP', 'Samaking', 'SunFi', 'Terra Lima', 'VetPower'
];

const FUNCTION_TO_COLUMN = {
  'Strategic Advisory':  'B',
  'Financial Modeling':  'C',
  'Fundraising':         'D',
  'Grantwriting':        'E',
  'Talent':              'F',
  'Product Development': 'G',
  'Research':            'H',
  'Commercial':          'I',
  'M&A Support':         'J',
  'Cross Cutting':       'K',
  'Ecosystem':           'L'
};

const FIRST_WEEK_LABEL_ROW = 3;
const BLOCK_SIZE           = 22;
const COMPANIES_OFFSET     = 1;
const tabName              = 'Elana'; //Hello team change this to match your name as it appears in the sheet

const now    = new Date();
const monday = new Date(now);
monday.setDate(now.getDate() - ((now.getDay() + 6) % 7));
monday.setHours(0, 0, 0, 0);
const weekOfMonth  = Math.ceil(monday.getDate() / 7);
const weekLabelRow = FIRST_WEEK_LABEL_ROW + (weekOfMonth - 1) * BLOCK_SIZE;

// ── LOOP THROUGH ALL ITEMS ────────────────────────────────────
return $input.all().map(i => {
  const item       = i.json;
  const company    = (item.company   || '').trim();
  const fn         = (item.function  || '').trim();
  const totalHours = item.total_hours || 0;

  const companyIndex = COMPANIES.findIndex(
    c => c.toLowerCase().trim() === company.toLowerCase().trim()
  );

  if (companyIndex === -1) {
    throw new Error(`Company "${company}" not found.`);
  }

  const column = FUNCTION_TO_COLUMN[fn];

  if (!column) {
    throw new Error(`Function "${fn}" not found.`);
  }

  const companyRow  = weekLabelRow + COMPANIES_OFFSET + companyIndex;
  const cellAddress = `${tabName}!${column}${companyRow}`;

  return {
    json: {
      cellAddress,
      total_hours: totalHours,
      _debug: { company, function: fn, column, companyRow, weekOfMonth, weekLabelRow }
    }
  };
});
